resource "azurerm_policy_definition" "deploy_law_agent" {
  name         = "deploy-vm-law-agent"
  policy_type  = "Custom"
  mode         = "Indexed"
  display_name = "Deploy Log Analytics Agent to Windows VMs"
  policy_rule  = file("${path.module}/policies/deploy-law-agent.json")
  parameters   = file("${path.module}/policies/deploy-law-agent-params.json")
}

resource "azurerm_management_group_policy_assignment" "deploy_law" {
  name                 = "deploy-law-agent"
  management_group_id  = var.corp_mg_id
  policy_definition_id = azurerm_policy_definition.deploy_law_agent.id
  location             = "eastus2"

  identity { type = "SystemAssigned" }

  parameters = jsonencode({
    logAnalyticsWorkspaceId = { value = var.log_analytics_workspace_id }
  })
}

# Grant managed identity Contributor at MG scope
resource "azurerm_role_assignment" "deploy_law_mi" {
  scope              = var.corp_mg_id
  role_definition_name = "Contributor"
  principal_id       = azurerm_management_group_policy_assignment.deploy_law.identity[0].principal_id
}

# Remediation task — depends on role assignment to avoid auth failures
resource "azurerm_management_group_policy_remediation" "deploy_law" {
  name                 = "remediate-law-agent"
  management_group_id  = var.corp_mg_id
  policy_assignment_id = azurerm_management_group_policy_assignment.deploy_law.id

  resource_discovery_mode = "ExistingNonCompliant"

  depends_on = [
    azurerm_role_assignment.deploy_law_mi
  ]
}

output "remediation_id" {
  value = azurerm_management_group_policy_remediation.deploy_law.id
}
